function solve(n, edges, k) {
    // Sort edges by weight in ascending order
    edges.sort((a, b) => a[2] - b[2]);

    // Initialize Union-Find structure
    const uf = new UnionFind(n);

    // Keep track of the maximum cost for each component
    const maxCosts = new Array(n).fill(0);

    // Process edges in order of increasing weight
    for (const [u, v, w] of edges) {
        const rootU = uf.find(u);
        const rootV = uf.find(v);

        if (rootU !== rootV) {
            // Merge the components
            uf.union(rootU, rootV);

            // Update the max cost of the new component
            maxCosts[uf.find(rootU)] = Math.max(maxCosts[rootU], maxCosts[rootV], w);
        } else {
            // The edge is within the same component, update the max cost
            maxCosts[rootU] = Math.max(maxCosts[rootU], w);
        }
    }

    // The answer is the maximum cost among all components
    return Math.max(...maxCosts);
}

